void solve(int CASE)
{
	int n, m; cin >> n >> m;
	ll l, r; cin >> l >> r;
	var a = vector<string>(n + 1);
	fa(i, 1, n)cin >> a[i], a[i] = ' ' + a[i];

	var dis = Vec3<int>(n + 1, m + 1, 2, INF);
	var Q = queue<tuple<int, int, int>>();
	dis[1][1][0] = 0;
	Q.push({ 1,1,0 });
	var vis = Vec3<bool>(n + 1, m + 1, 2);
	while (Q.size()) {
		var[x, y, st] = Q.front();
		Q.pop();
		if (vis[x][y][st])continue;
		vis[x][y][st] = 1;
		fa(k, 0, 7) {
			int nx = x + dx[k];
			int ny = y + dy[k];
			if (nx < 1 or nx > n or ny < 1 or ny > m or a[nx][ny] == '0')continue;
			if (dis[nx][ny][st ^ 1] > dis[x][y][st] + 1) {
				dis[nx][ny][st ^ 1] = dis[x][y][st] + 1;
				Q.push({ nx,ny,st ^ 1 });
			}
		}
	}

	if (dis[n][m][0] >= INF and dis[n][m][1] >= INF) {
		cout << -1 << endl;
		return;
	}

	var cal = [&](ll dist)->ll {
		if (dist >= INF)return LNF;
		if (dist % r == 0)return dist / r;

		ll left = r - dist % r;
		if (left % 2 == 0 or r - l >= 1)return dist / r + 1;

		// 此时 l == r，left % 2 == 1
		// dist + 2 * y = r * x
		// r * x - dist = 2 * y
		// y = (r * x - dist) / 2
		ll res = (dist + r - 1) / r;
		bool ok = 0;
		fa(add, 0, 2) {
			if ((r * (res + add) - dist) % 2 == 0) {
				res += add;
				ok = 1;
				break;
			}
		}
		if (ok)return res;
		else return LNF;
		};
	ll ans = LNF;
	ans = min(ans, cal(dis[n][m][0]));
	ans = min(ans, cal(dis[n][m][1]));

	if (ans == LNF)cout << -1 << endl;
	else cout << ans << endl;
	return;
}
